from flask import Flask, request, jsonify
from flask_oauthlib.provider import OAuth2Provider

app = Flask(__name__)
app.config['SECRET_KEY'] = 'some secret'
oauth = OAuth2Provider(app)

# you can register multiple clients at once by passing a list of dictionaries:
clients = [{'client_id': '1234',  # client id, public is enough for most cases
            'client_secret': 'abcd',  # client secret
            'redirect_uris': ['http://localhost:5000/authorize'],  # allowed redirect urls after successful authorization
            }, ]

@app.route('/oauth/token', methods=['POST'])
@oauth.token_handler
def access_token():
    return None

@oauth.clientgetter
def load_client(client_id):
    for client in clients:
        if client['client_id'] == client_id:
            return client
    return None

@app.route('/authorize', methods=['GET', 'POST'])
@oauth.authorize_handler
def authorize(client_id):
    # user has to login and authorize the app
    if request.method == 'GET':
        return jsonify({'redirect_uri': 'http://localhost:5000/authorize', 
                        'client_id': client_id, 
                        '_csrf_token': ''})

    confirm = request.form['confirm']
    # user has denied the authorization
    if confirm != 'yes':
        return jsonify({'status': 'error', 'message': 'User denied authorization'}), 403
    
    client = load_client(client_id)
    if not client:
        return jsonify({'status': 'error', 'message': 'Invalid client id'}), 401
    
    redirect_uri = request.form['redirect_uri']
    for uri in client['redirect_uris']:
        if redirect_uri.startswith(uri):
            return jsonify({'status': 'success', 'message': 'User authorized the application'}), 200
    
    return jsonify({'status': 'error', 'message': 'Invalid redirect uri'}), 401